def search(conditions):
    if not conditions:
        return "SELECT * FROM users"
    
    # Allowlist of valid fields and operators
    valid_fields = {'age', 'city', 'name', 'email', 'salary'}
    valid_operators = {'=', '>', '<', '>=', '<=', 'LIKE', '!='}
    
    # Build WHERE clause
    where_parts = []
    params = []
    
    for condition in conditions:
        field = condition.get('field')
        op = condition.get('op')
        value = condition.get('value')
        
        # Validate field and operator
        if field not in valid_fields:
            raise ValueError(f"Invalid field: {field}")
        if op not in valid_operators:
            raise ValueError(f"Invalid operator: {op}")
        
        # Handle LIKE operator with wildcards
        if op == 'LIKE':
            if not isinstance(value, str):
                raise ValueError("LIKE operator requires string value")
            # Escape % and _ characters for LIKE
            escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
            where_parts.append(f"{field} LIKE ?")
            params.append(f"%{escaped_value}%")
        else:
            where_parts.append(f"{field} {op} ?")
            params.append(value)
    
    # Construct final query
    query = "SELECT * FROM users WHERE " + " AND ".join(where_parts)
    
    return query, params

